BEGIN; CREATE OR REPLACE FUNCTION public.can_manage_accounting_debt() RETURNS boolean LANGUAGE sql SECURITY DEFINER SET search_path = public STABLE AS $$ SELECT public.is_admin() OR EXISTS (SELECT 1 FROM public.profiles p WHERE p.id = auth.uid() AND p.department = 'accounting' AND COALESCE(p.is_active, false) = true AND COALESCE(p.is_approved, true) = true AND p.deleted_at IS NULL); $$; GRANT EXECUTE ON FUNCTION public.can_manage_accounting_debt() TO authenticated; CREATE TABLE IF NOT EXISTS public.accounting_debt_invoices (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), debt_type text NOT NULL CHECK (debt_type IN ('receivable','payable')), partner_kind text NOT NULL DEFAULT 'customer' CHECK (partner_kind IN ('customer','supplier')), customer_id uuid NULL REFERENCES public.customers(id), partner_code text NULL, partner_name text NOT NULL, invoice_no text NOT NULL, invoice_date date NOT NULL, payment_term_days integer NOT NULL DEFAULT 30 CHECK (payment_term_days BETWEEN 0 AND 3650), due_date date NOT NULL, amount numeric(18,2) NOT NULL CHECK (amount >= 0), currency text NOT NULL DEFAULT 'VND', po_no text NULL, reference_no text NULL, status text NOT NULL DEFAULT 'open' CHECK (status IN ('open','cancelled')), note text NULL, cancel_reason text NULL, cancelled_at timestamptz NULL, cancelled_by uuid NULL REFERENCES public.profiles(id), created_at timestamptz NOT NULL DEFAULT now(), created_by uuid NULL REFERENCES public.profiles(id), updated_at timestamptz NOT NULL DEFAULT now(), updated_by uuid NULL REFERENCES public.profiles(id), deleted_at timestamptz NULL, deleted_by uuid NULL REFERENCES public.profiles(id), CHECK ((debt_type = 'receivable' AND customer_id IS NOT NULL AND partner_kind = 'customer') OR (debt_type = 'payable' AND customer_id IS NULL AND partner_kind = 'supplier'))); CREATE TABLE IF NOT EXISTS public.accounting_debt_payments (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), invoice_id uuid NOT NULL REFERENCES public.accounting_debt_invoices(id), payment_date date NOT NULL, amount numeric(18,2) NOT NULL CHECK (amount > 0), method text NOT NULL DEFAULT 'bank_transfer' CHECK (method IN ('bank_transfer','cash','offset','other')), reference_no text NULL, note text NULL, created_at timestamptz NOT NULL DEFAULT now(), created_by uuid NULL REFERENCES public.profiles(id), updated_at timestamptz NOT NULL DEFAULT now(), updated_by uuid NULL REFERENCES public.profiles(id), deleted_at timestamptz NULL, deleted_by uuid NULL REFERENCES public.profiles(id)); CREATE TABLE IF NOT EXISTS public.accounting_debt_invoice_audit (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), invoice_id uuid NOT NULL REFERENCES public.accounting_debt_invoices(id), action text NOT NULL, old_data jsonb NULL, new_data jsonb NULL, changed_at timestamptz NOT NULL DEFAULT now(), changed_by uuid NULL REFERENCES public.profiles(id)); CREATE INDEX IF NOT EXISTS idx_acc_debt_invoices_type_due ON public.accounting_debt_invoices(debt_type, due_date) WHERE deleted_at IS NULL; CREATE INDEX IF NOT EXISTS idx_acc_debt_invoices_customer ON public.accounting_debt_invoices(customer_id) WHERE deleted_at IS NULL; CREATE INDEX IF NOT EXISTS idx_acc_debt_invoices_status ON public.accounting_debt_invoices(status) WHERE deleted_at IS NULL; CREATE INDEX IF NOT EXISTS idx_acc_debt_payments_invoice ON public.accounting_debt_payments(invoice_id) WHERE deleted_at IS NULL; CREATE OR REPLACE FUNCTION public.accounting_debt_touch_row() RETURNS trigger LANGUAGE plpgsql SET search_path = public AS $$ BEGIN IF TG_OP = 'INSERT' THEN NEW.created_at := COALESCE(NEW.created_at, now()); NEW.created_by := COALESCE(NEW.created_by, auth.uid()); END IF; NEW.updated_at := now(); NEW.updated_by := auth.uid(); RETURN NEW; END; $$; CREATE OR REPLACE FUNCTION public.accounting_debt_audit_invoice_update() RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$ DECLARE v_action text := 'updated'; BEGIN IF OLD.deleted_at IS NULL AND NEW.deleted_at IS NOT NULL THEN v_action := 'soft_deleted'; ELSIF OLD.status IS DISTINCT FROM NEW.status AND NEW.status = 'cancelled' THEN v_action := 'cancelled'; END IF; INSERT INTO public.accounting_debt_invoice_audit(invoice_id, action, old_data, new_data, changed_by) VALUES (NEW.id, v_action, to_jsonb(OLD), to_jsonb(NEW), auth.uid()); RETURN NEW; END; $$; CREATE OR REPLACE FUNCTION public.accounting_debt_block_hard_delete() RETURNS trigger LANGUAGE plpgsql SET search_path = public AS $$ BEGIN RAISE EXCEPTION 'Bi chan de bao ve du lieu cong no: khong duoc xoa cung. Hay huy hoac danh dau xoa mem.'; END; $$; DROP TRIGGER IF EXISTS trg_acc_debt_invoices_touch ON public.accounting_debt_invoices; CREATE TRIGGER trg_acc_debt_invoices_touch BEFORE INSERT OR UPDATE ON public.accounting_debt_invoices FOR EACH ROW EXECUTE FUNCTION public.accounting_debt_touch_row(); DROP TRIGGER IF EXISTS trg_acc_debt_payments_touch ON public.accounting_debt_payments; CREATE TRIGGER trg_acc_debt_payments_touch BEFORE INSERT OR UPDATE ON public.accounting_debt_payments FOR EACH ROW EXECUTE FUNCTION public.accounting_debt_touch_row(); DROP TRIGGER IF EXISTS trg_acc_debt_invoices_audit ON public.accounting_debt_invoices; CREATE TRIGGER trg_acc_debt_invoices_audit AFTER UPDATE ON public.accounting_debt_invoices FOR EACH ROW WHEN (OLD IS DISTINCT FROM NEW) EXECUTE FUNCTION public.accounting_debt_audit_invoice_update(); DROP TRIGGER IF EXISTS trg_acc_debt_invoices_block_delete ON public.accounting_debt_invoices; CREATE TRIGGER trg_acc_debt_invoices_block_delete BEFORE DELETE ON public.accounting_debt_invoices FOR EACH ROW EXECUTE FUNCTION public.accounting_debt_block_hard_delete(); DROP TRIGGER IF EXISTS trg_acc_debt_payments_block_delete ON public.accounting_debt_payments; CREATE TRIGGER trg_acc_debt_payments_block_delete BEFORE DELETE ON public.accounting_debt_payments FOR EACH ROW EXECUTE FUNCTION public.accounting_debt_block_hard_delete(); ALTER TABLE public.accounting_debt_invoices ENABLE ROW LEVEL SECURITY; ALTER TABLE public.accounting_debt_payments ENABLE ROW LEVEL SECURITY; ALTER TABLE public.accounting_debt_invoice_audit ENABLE ROW LEVEL SECURITY; DROP POLICY IF EXISTS "acc_debt_invoices_select" ON public.accounting_debt_invoices; CREATE POLICY "acc_debt_invoices_select" ON public.accounting_debt_invoices FOR SELECT TO authenticated USING (public.can_manage_accounting_debt()); DROP POLICY IF EXISTS "acc_debt_invoices_insert" ON public.accounting_debt_invoices; CREATE POLICY "acc_debt_invoices_insert" ON public.accounting_debt_invoices FOR INSERT TO authenticated WITH CHECK (public.can_manage_accounting_debt()); DROP POLICY IF EXISTS "acc_debt_invoices_update" ON public.accounting_debt_invoices; CREATE POLICY "acc_debt_invoices_update" ON public.accounting_debt_invoices FOR UPDATE TO authenticated USING (public.can_manage_accounting_debt()) WITH CHECK (public.can_manage_accounting_debt()); DROP POLICY IF EXISTS "acc_debt_payments_select" ON public.accounting_debt_payments; CREATE POLICY "acc_debt_payments_select" ON public.accounting_debt_payments FOR SELECT TO authenticated USING (public.can_manage_accounting_debt()); DROP POLICY IF EXISTS "acc_debt_payments_insert" ON public.accounting_debt_payments; CREATE POLICY "acc_debt_payments_insert" ON public.accounting_debt_payments FOR INSERT TO authenticated WITH CHECK (public.can_manage_accounting_debt()); DROP POLICY IF EXISTS "acc_debt_payments_update" ON public.accounting_debt_payments; CREATE POLICY "acc_debt_payments_update" ON public.accounting_debt_payments FOR UPDATE TO authenticated USING (public.can_manage_accounting_debt()) WITH CHECK (public.can_manage_accounting_debt()); DROP POLICY IF EXISTS "acc_debt_audit_select" ON public.accounting_debt_invoice_audit; CREATE POLICY "acc_debt_audit_select" ON public.accounting_debt_invoice_audit FOR SELECT TO authenticated USING (public.can_manage_accounting_debt()); DROP POLICY IF EXISTS "acc_debt_audit_insert" ON public.accounting_debt_invoice_audit; CREATE POLICY "acc_debt_audit_insert" ON public.accounting_debt_invoice_audit FOR INSERT TO authenticated WITH CHECK (public.can_manage_accounting_debt()); GRANT SELECT, INSERT, UPDATE ON public.accounting_debt_invoices TO authenticated; GRANT SELECT, INSERT, UPDATE ON public.accounting_debt_payments TO authenticated; GRANT SELECT, INSERT ON public.accounting_debt_invoice_audit TO authenticated; NOTIFY pgrst, 'reload schema'; COMMIT;
